function gtag(){dataLayer.push(arguments);}
gtag('js', new Date());

gtag('config', 'G-3Y7D149PN0');

div.script:
function searchAutocomplete(autofocus = false) {
    return {
        query: '',
        suggestions: [],
        open: false,
        selectedIndex: -1,

        init() {
            // Only autofocus on non-touch devices
            if (autofocus && !this.isTouchDevice()) {
                this.$refs.searchInput.focus();
            }
        },

        isTouchDevice() {
            return (('ontouchstart' in window) ||
                    (navigator.maxTouchPoints > 0) ||
                    (navigator.msMaxTouchPoints > 0));
        },

        async fetchSuggestions() {
            if (this.query.length < 1) {
                this.suggestions = [];
                this.open = false;
                this.selectedIndex = -1;
                return;
            }

            try {
                const response = await fetch(`/api/search/suggestions?q=${encodeURIComponent(this.query)}`);
                this.suggestions = await response.json();
                this.open = this.suggestions.length > 0;
                this.selectedIndex = -1;
            } catch (error) {
                console.error('Error fetching suggestions:', error);
                this.suggestions = [];
                this.open = false;
            }
        },

        selectNext() {
            if (this.suggestions.length === 0) return;
            this.selectedIndex = (this.selectedIndex + 1) % this.suggestions.length;
        },

        selectPrevious() {
            if (this.suggestions.length === 0) return;
            this.selectedIndex = this.selectedIndex <= 0 ? this.suggestions.length - 1 : this.selectedIndex - 1;
        },

        submitSelected() {
            if (this.selectedIndex >= 0 && this.suggestions[this.selectedIndex]) {
                this.navigateToSearch(this.suggestions[this.selectedIndex].name);
            } else {
                // Submit the form normally
                this.$el.closest('form').submit();
            }
        },

        navigateToSearch(query) {
            window.location.href = `https://worldvectorlogo.com/search?q=${encodeURIComponent(query)}`;
        }
    }
}

div.x-data:
{
                    copying: false,
                    copied: false,
                    svgUrl: 'https:\/\/worldvectorlogo.com\/logo\/office-1\/svg-content',
                    trackUrl: 'https:\/\/worldvectorlogo.com\/logo\/office-1\/download',
                    async copyLogo() {
                        if (this.copying) {
                            return;
                        }

                        this.copying = true;

                        try {
                            await window.copyLogoFormat(this.svgUrl, this.trackUrl);
                            this.copied = true;
                            setTimeout(() => { this.copied = false; }, 2000);
                        } catch {
                            // Clipboard API may fail in insecure contexts
                        } finally {
                            this.copying = false;
                        }
                    },
                 }

